const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

let projects = {};

function getProjectById(projectId) {
  return projects[projectId] || null;
}

function getProjectByName(name) {
  const project = Object.values(projects).find(p => p.name === name);
  return project || null;
}

function createProject(name) {
  if (!name) {
    return sendError(null, 400, 'INVALID_NAME', 'Name is required');
  }
  const projectId = randomUUID();
  projects[projectId] = { id: projectId, name, members: [], tasks: [] };
  return projects[projectId];
}

function addMemberToProject(projectId, userId, role) {
  const project = getProjectById(projectId);
  if (!project) {
    return sendError(null, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  if (project.members.some(member => member.userId === userId)) {
    return sendError(null, 409, 'MEMBER_EXISTS', 'Member already exists in the project');
  }
  project.members.push({ userId, role });
  return project;
}

module.exports = {
  getProjectById,
  getProjectByName,
  createProject,
  addMemberToProject
};
const __botEvalProjectsDupGuard = module.exports.createProject;
module.exports.createProject = async function createProject(name) {
  const normalized = String(name || '').trim();
  let existing = null;
  if (typeof module.exports.getProjectByName === 'function') {
    existing = await module.exports.getProjectByName(normalized);

  }
  if (existing) return null;
  if (typeof __botEvalProjectsDupGuard === 'function') return __botEvalProjectsDupGuard(normalized);
  return null;
};

const { sendError } = require('../../lib/errors');

function updateTask(project, taskId, status) {
  const task = project.tasks.find(task => task.id === taskId);
  if (!task) {
    return sendError(null, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  if (status !== 'todo' && status !== 'done') {
    return sendError(null, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }
  task.status = status;
  return project;
}

module.exports = {
  updateTask
};
